function createBaseGetMessageResponse(): GetMessageResponse {
  return { message: "", success: false, status: 0, data: [] };
}

export const GetMessageResponse: MessageFns<GetMessageResponse> = {
  encode(message: GetMessageResponse, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.message !== "") {
      writer.uint32(10).string(message.message);
    }
    if (message.success !== false) {
      writer.uint32(16).bool(message.success);
    }
    if (message.status !== 0) {
      writer.uint32(24).int32(message.status);
    }
    for (const v of message.data) {
      MessagePayload.encode(v!, writer.uint32(34).fork()).join();
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): GetMessageResponse {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseGetMessageResponse();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 10) {
            break;
          }

          message.message = reader.string();
          continue;
        }
        case 2: {
          if (tag !== 16) {
            break;
          }

          message.success = reader.bool();
          continue;
        }
        case 3: {
          if (tag !== 24) {
            break;
          }

          message.status = reader.int32();
          continue;
        }
        case 4: {
          if (tag !== 34) {
            break;
          }

          message.data.push(MessagePayload.decode(reader, reader.uint32()));
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): GetMessageResponse {
    return {
      message: isSet(object.message) ? globalThis.String(object.message) : "",
      success: isSet(object.success) ? globalThis.Boolean(object.success) : false,
      status: isSet(object.status) ? globalThis.Number(object.status) : 0,
      data: globalThis.Array.isArray(object?.data) ? object.data.map((e: any) => MessagePayload.fromJSON(e)) : [],
    };
  },

  toJSON(message: GetMessageResponse): unknown {
    const obj: any = {};
    if (message.message !== "") {
      obj.message = message.message;
    }
    if (message.success !== false) {
      obj.success = message.success;
    }
    if (message.status !== 0) {
      obj.status = Math.round(message.status);
    }
    if (message.data?.length) {
      obj.data = message.data.map((e) => MessagePayload.toJSON(e));
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<GetMessageResponse>, I>>(base?: I): GetMessageResponse {
    return GetMessageResponse.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<GetMessageResponse>, I>>(object: I): GetMessageResponse {
    const message = createBaseGetMessageResponse();
    message.message = object.message ?? "";
    message.success = object.success ?? false;
    message.status = object.status ?? 0;
    message.data = object.data?.map((e) => MessagePayload.fromPartial(e)) || [];
    return message;
  },
};

